import{_ as e,o as t,c as o,a}from"./app.076af709.js";const u=JSON.parse('{"title":"Judges v. bgbba, Aug 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/judges_v_bgbba_aug_2018.md","lastUpdated":1666477380000}'),r={name:"government/court-cases-precedents/judges_v_bgbba_aug_2018.md"},s=a('<h1 id="judges-v-bgbba-aug-2018" tabindex="-1">Judges v. bgbba, Aug 2018 <a class="header-anchor" href="#judges-v-bgbba-aug-2018" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With Feathercrown presiding, Judges requested a sentence for his pearl. Judges was found guilty of Treason and Association with Enemies and sentenced him to 5 months Prison Pearl considered time served, to be released immediate, and put on probation.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>Feathercrown</strong>:</p><blockquote><p>Judges has requested a trial from bgbba about his pearling. The result of the trial will be decided by me, as Judges has chosen me as their judge. The verdict may be appealed to the Alcuahtl, bgbba, if Judges requests it.</p></blockquote><blockquote><p>bgbba, please explain what Judges has done that warrants his pearling, with proof.</p></blockquote><p><strong>bgbba</strong>:</p><blockquote><p>I&#39;m calling Modshot as a witness</p></blockquote><p><strong>Modshot</strong>:</p><blockquote><p>You want the proof?</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p><a href="https://i.gyazo.com/thumb/1200/f3d8fa4821230f0304997dc03574e83b-png.jpg" target="_blank" rel="noreferrer">https://i.gyazo.com/thumb/1200/f3d8fa4821230f0304997dc03574e83b-png.jpg</a></p></blockquote><blockquote><p><a href="https://i.gyazo.com/thumb/1200/e4f943838591e19d2975f3ede9319c52-png.jpg" target="_blank" rel="noreferrer">https://i.gyazo.com/thumb/1200/e4f943838591e19d2975f3ede9319c52-png.jpg</a></p></blockquote><blockquote><p><a href="https://i.gyazo.com/thumb/1200/fd36d39d18b6e21eb668d818ca81744b-png.jpg" target="_blank" rel="noreferrer">https://i.gyazo.com/thumb/1200/fd36d39d18b6e21eb668d818ca81744b-png.jpg</a></p></blockquote><blockquote><p><a href="https://i.gyazo.com/thumb/1200/6890351851221486fcee91ecb432a60c-png.jpg" target="_blank" rel="noreferrer">https://i.gyazo.com/thumb/1200/6890351851221486fcee91ecb432a60c-png.jpg</a></p></blockquote><p><strong>Feathercrown</strong>:</p><blockquote><p>Thanks for linking it here, Orange. bgbba, do you wish to provide any more proof?</p></blockquote><p>[deleted]:</p><blockquote><p>[deleted]</p></blockquote><p><strong>Feathercrown</strong>:</p><blockquote><p>Judges, please explain your side of the story. Proof may be used.</p></blockquote><p><strong>Judges</strong>:</p><blockquote><p>Alright, sorry for taking so long I&#39;ve been trying to get in contact with Modshot who is my main witness and hes been offline. Anyway, the main point I would like to make is that that situation was already settled with Modshot and was caused by Bg removing me from the discord randomly (which Modshot understood and added me back). Bg doesn&#39;t want me pearled because of that though. He wants me pearled because of the post on the sub of him denying me to be in the discord and him acting very rude to me which hurt his PR. You can see this clearly in these screenshots <a href="https://imgur.com/a/BV6hKWP" target="_blank" rel="noreferrer">https://imgur.com/a/BV6hKWP</a>.</p></blockquote><blockquote><p>I would further like to state that Bg didn&#39;t even remember that I was pearled until I asked him to unpearl me. <a href="https://gyazo.com/d362a5776acfa971beb34bd52a0e9b1c" target="_blank" rel="noreferrer">https://gyazo.com/d362a5776acfa971beb34bd52a0e9b1c</a></p></blockquote><blockquote><p>Anyway thats all my proof for this situation however I would also like to state that Bg has been trying to deny me my rights of a trial all throughout this situation which Feather himself has seen. I can provide proof of that as well if needed.</p></blockquote><p><strong>Feathercrown</strong>:</p><blockquote><p>Ok so after much deliberation with Judges, Bgbba, and Modshot, I have chosen to sentence Judges to 5 months of pearl time for treason and association with enemies. However, he has already served more than said pearl time, and shall be released immediately. Given that his pearl was mishandled and he does seem genuinely interested in Yoahtl&#39;s future, if Judges wishes, he may reenter Yoahtl on a probationary period of 1.5 months within which any disruption of the community or major crime will result in his exile from Yoahtl.</p></blockquote>',28),n=[s];function i(d,h,c,l,p,g){return t(),o("div",null,n)}const m=e(r,[["render",i]]);export{u as __pageData,m as default};
